import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

export default function Home() {

  const nav = useNavigate();

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* LEFT */}

        <div style={styles.left}>

          <p style={styles.smallText}>
            Daily Worker Hiring Platform
          </p>

          <h1 style={styles.heading}>
            Hire Skilled
            <br />
            Workers Near You
          </h1>

          <p style={styles.desc}>
            Simple and fast way to connect
            with trusted workers for daily jobs.
          </p>

          <div style={styles.buttonRow}>

            <button
              style={styles.loginBtn}
              onClick={() => nav("/login")}
            >
              Login
            </button>

            <button
              style={styles.registerBtn}
              onClick={() => nav("/register")}
            >
              Register
            </button>

          </div>

        </div>

        {/* RIGHT */}

        <div style={styles.right}>

          <div style={styles.box}>
            ⚡ Electrician
          </div>

          <div style={styles.box}>
            🚿 Plumber
          </div>

          <div style={styles.box}>
            🎨 Painter
          </div>

          <div style={styles.box}>
            🪚 Carpenter
          </div>

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f8fafc",
    fontFamily: "Arial"
  },

  container: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "80px",
    gap: "50px"
  },

  left: {
    flex: 1
  },

  smallText: {
    color: "#2563eb",
    fontSize: "14px",
    marginBottom: "15px"
  },

  heading: {
    fontSize: "46px",
    lineHeight: "60px",
    color: "#111827",
    marginBottom: "20px"
  },

  desc: {
    color: "#6b7280",
    fontSize: "16px",
    lineHeight: "28px",
    marginBottom: "30px",
    maxWidth: "450px"
  },

  buttonRow: {
    display: "flex",
    gap: "15px"
  },

  loginBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "12px 24px",
    borderRadius: "8px",
    cursor: "pointer"
  },

  registerBtn: {
    background: "white",
    border: "1px solid #d1d5db",
    padding: "12px 24px",
    borderRadius: "8px",
    cursor: "pointer"
  },

  right: {
    width: "320px",
    display: "flex",
    flexDirection: "column",
    gap: "15px"
  },

  box: {
    background: "white",
    padding: "18px",
    borderRadius: "12px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.05)",
    fontSize: "15px",
    color: "#374151"
  }

};
